Example <p>Step 1. Add pom.xml  new dependency. <pre><code>&lt;dependency&gt;
&lt;groupId&gt;org.springframework.boot&lt;/groupId&gt;
&lt;artifactId&gt;spring-boot-starter-actuator&lt;/artifactId&gt;
&lt;/dependency&gt;
</code></pre> Step 2. Add permission to  SecurityConfig.java  <pre><code>.antMatchers("/actuator/metrics/**").permitAll()
</code></pre> Step 3. Add new environment to  application.yml <pre><code>    management:
        endpoint:
            metrics:
                enabled: true
    endpoints:
        enabled-by-default: true
        web:
            exposure:
                include: 'metrics'
</code></pre> Step 4. Add description custom metrics:screen,bc,crudmaAction,error,user.</p> <p>Custom metrics start name: "platform-requests"</p> <pre><code>package org.demo.conf.cxbox.metrics;
import io.micrometer.core.instrument.Counter;
import io.micrometer.core.instrument.MeterRegistry;
import java.util.Optional;
import java.util.stream.Stream;
import org.cxbox.core.crudma.CrudmaActionHolder.CrudmaAction;
import org.cxbox.core.crudma.CrudmaEvent;
import org.cxbox.core.crudma.bc.BusinessComponent;
import org.demo.conf.security.cxboxkeycloak.CxboxKeycloakAccount;
import org.springframework.context.ApplicationListener;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContext;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Component;
@Component
public class CrudmaEventListener implements ApplicationListener&lt;CrudmaEvent&gt; {
public static final String UNDEFINED = "undefined";
private final MeterRegistry registry;
public CrudmaEventListener(MeterRegistry registry) {
this.registry = registry;
registry.counter("platform-requests");
}
@Override
public final void onApplicationEvent(final CrudmaEvent event) {
final CrudmaAction crudmaAction = event.getCrudmaAction();
final BusinessComponent bc = crudmaAction.getBc();
Counter counter = registry.counter(
"platform-requests",
"screen", Optional.ofNullable(bc.getHierarchy().getScreenName()).orElse(UNDEFINED),
"bc", Optional.ofNullable(bc.getName()).orElse(UNDEFINED),
"crudmaAction", Optional.ofNullable(crudmaAction.getName()).orElse(UNDEFINED),
"user", Optional.ofNullable(getUserLogin()).orElse(UNDEFINED),
"error", event.getException() == null ? "false" : "true"
);
counter.increment();
}
public static String getUserLogin() {
return Stream.of(SecurityContextHolder.getContext())
.map(SecurityContext::getAuthentication)
.map(Authentication::getDetails)
.filter(CxboxKeycloakAccount.class::isInstance)
.map(CxboxKeycloakAccount.class::cast)
.findFirst()
.map(CxboxKeycloakAccount::getUsername)
.orElse(null);
}
}
</code></pre>

Example <p>Step 1. Add pom.xml  new dependency. <pre><code>&lt;dependency&gt;
&lt;groupId&gt;org.springframework.boot&lt;/groupId&gt;
&lt;artifactId&gt;spring-boot-starter-mail&lt;/artifactId&gt;
&lt;/dependency&gt;
</code></pre> Step 2. Add new environment to  application.yml <pre><code>spring:
    mail:
        host: ${MAIL_HOST:false}  
        port: 587
        username: ${MAIL_USER:}  
        password: ${MAIL_PASSWORD:} 
        properties:
            mail:
                smtp:
                    auth: true
                starttls:
                    enable: true
</code></pre> Step 3. Add service MailSendingService</p> <pre><code>package org.demo.service;
import static org.cxbox.api.service.session.InternalAuthorizationService.VANILLA;
import java.time.LocalDateTime;
import java.util.Optional;
import lombok.RequiredArgsConstructor;
import org.cxbox.api.service.session.InternalAuthorizationService;
import org.cxbox.core.dto.DrillDownType;
import org.cxbox.model.core.entity.User;
import org.demo.dto.SocketNotificationDTO;
import org.demo.dto.SocketNotificationErrorDTO;
import org.demo.dto.enums.SocketNotificationErrorType;
import org.springframework.boot.autoconfigure.mail.MailProperties;
import org.springframework.mail.MailException;
import org.springframework.mail.MailParseException;
import org.springframework.mail.MailPreparationException;
import org.springframework.mail.SimpleMailMessage;
import org.springframework.mail.javamail.JavaMailSender;
import org.springframework.scheduling.annotation.Async;
import org.springframework.stereotype.Service;
@Service
@RequiredArgsConstructor
public class MailSendingService {
private final Optional&lt;JavaMailSender&gt; javaMailSender;
private final Optional&lt;MailProperties&gt; mailProperties;
private final NotificationService notificationService;
private final InternalAuthorizationService authzService;
private static final String HTTP = "http://";
@Async
public void send(Optional&lt;String&gt; mailTo, String subject, String message, User currentUser) {
if (mailTo.isPresent() &amp;&amp; mailSenderEnabled()) {
try {
SimpleMailMessage simpleMailMessage = new SimpleMailMessage();
simpleMailMessage.setFrom(mailProperties.get().getUsername());
simpleMailMessage.setText(message);
simpleMailMessage.setTo(mailTo.get());
simpleMailMessage.setSubject(subject);
javaMailSender.get().send(simpleMailMessage);
authzService.loginAs(authzService.createAuthentication(VANILLA));
String link = mailTo.map(mail -&gt; mail.substring(mail.indexOf("@") + 1)).orElse("");
notificationService.sendAndSave(SocketNotificationDTO.builder()
.title("Successful")
.text("Email sent to " + mailTo.orElse(""))
.drillDownType(DrillDownType.EXTERNAL_NEW.getValue())
.drillDownLabel(link)
.drillDownLink(HTTP + link)
.time(LocalDateTime.now())
.build(), currentUser);
} catch (MailParseException | MailPreparationException e) {
notificationService.sendAndSave(
getSocketNotificationDTOWithError(SocketNotificationErrorType.BusinessError, e.getMessage(),
mailTo.orElse("")
),
currentUser
);
} catch (MailException e) {
notificationService.sendAndSave(
getSocketNotificationDTOWithError(SocketNotificationErrorType.SystemError, e.getMessage(),
mailTo.orElse("")
),
currentUser
);
}
}
}
private boolean mailSenderEnabled() {
return javaMailSender.isPresent()
&amp;&amp; mailProperties.isPresent()
&amp;&amp; mailProperties.get().getHost() != null
&amp;&amp; !mailProperties.get().getHost().isBlank();
}
private SocketNotificationDTO getSocketNotificationDTOWithError(SocketNotificationErrorType type,
String message, String mailTo) {
return SocketNotificationDTO.builder()
.title("Not Successful")
.text("Email not sent to " + mailTo)
.time(LocalDateTime.now())
.error(new SocketNotificationErrorDTO(type, message))
.build();
}
}
</code></pre>

Example <ul> <li> <p>Step 1. Add pom.xml  new dependency. <pre><code>&lt;dependency&gt;
&lt;groupId&gt;org.springframework.boot&lt;/groupId&gt;
&lt;artifactId&gt;spring-boot-starter-websocket&lt;/artifactId&gt;
&lt;/dependency&gt;
</code></pre></p> </li> <li> <p>Step 2. Add new environment to  application.yml <pre><code>websocket:
    endpointToConnect: /websocketnotification
    topic: /user/queue/websocket.reply
</code></pre></p> </li> </ul> Step 3. SimpleBrokerStep 3. ActiveMQ <p>The default broker is SimpleBroker Spring implementation.</p> <p>see more STOMP Protocols</p> <ul> <li> <p>see more ActiveMQ</p> <ul> <li> <p>Step 3.1. Add pom.xml  new dependency.</p> <pre><code>```
    &lt;dependency&gt;
      &lt;groupId&gt;org.springframework.boot&lt;/groupId&gt;
      &lt;artifactId&gt;spring-boot-starter-activemq&lt;/artifactId&gt;
    &lt;/dependency&gt;
    &lt;dependency&gt;
      &lt;groupId&gt;org.springframework.boot&lt;/groupId&gt;
      &lt;artifactId&gt;spring-boot-starter-reactor-netty&lt;/artifactId&gt;
    &lt;/dependency&gt;
```
</code></pre> </li> <li> <p>Step 3.2. Convert the ACTIVEMQ_BROKER_TYPE environment variable to the 'activemq' value</p> <pre><code>```
ACTIVEMQ_BROKER_TYPE:activemq
```
</code></pre> </li> <li> <p>Step 3.3 Other configurations:</p> <pre><code>```
ACTIVEMQ_ADMIN_LOGIN: The default admin login is 'admin'
ACTIVEMQ_ADMIN_PASSWORD: The default administrator password is 'admin'
ACTIVEMQ_HOST: The default connection host is 'activemq'
ACTIVEMQ_PORT: The default connection port is '61616'
STOMP_PORT: The default STOMP connection port is '61613'
```
</code></pre> </li> </ul> </li> </ul> <ul> <li> <p>Step 4. Add WebSocketConfig.java</p> <pre><code>import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Configuration;
import org.springframework.messaging.simp.config.MessageBrokerRegistry;
import org.springframework.web.socket.config.annotation.EnableWebSocketMessageBroker;
import org.springframework.web.socket.config.annotation.StompEndpointRegistry;
import org.springframework.web.socket.config.annotation.WebSocketMessageBrokerConfigurer;
@Configuration
@EnableWebSocketMessageBroker
public class WebSocketConfig implements WebSocketMessageBrokerConfigurer {
@Value("${spring.websocket.topic}")
private String topic;
@Value("${spring.websocket.endpointToConnect}")
private String endpointToConnect;
@Value("${cxbox.api.path}")
private String api;
@Override
public void configureMessageBroker(MessageBrokerRegistry config) {
config.enableSimpleBroker(topic);
}
@Override
public void registerStompEndpoints(StompEndpointRegistry registry) {
registry.addEndpoint(api + endpointToConnect);
}
}
</code></pre> </li> </ul>

