throw new IllegalStateException();
}
@NonNull
private List&lt;MyExampleDTO&gt; getStats() {
List&lt;MyExampleDTO&gt; result = new ArrayList&lt;&gt;(ROWS_TOTAL);
MyExampleDTO newRow = new MyExampleDTO()
.setTitle("All record")
